<?php

// Define the base directory for templates
define('TEMPLATE_DIR', __DIR__ . '/templates/');

// --- Configuration ---
// List of allowed pages to prevent directory traversal and arbitrary file inclusion.
// Keys are the 'page' parameter values, values are the actual file names (without .php extension).
$allowedPages = [
    'home' => 'home',
    'about' => 'about',
    'contact' => 'contact',
    'services' => 'services',
    // Add more pages as needed
];

// Default page to load if 'page' parameter is not set or not allowed
$defaultPage = 'home';

// --- Routing Logic ---

$requestedPage = $_GET['page'] ?? null;
$pageToLoad = $defaultPage;

// Check if the requested page is in our allowed list
if ($requestedPage && array_key_exists($requestedPage, $allowedPages)) {
    $pageToLoad = $allowedPages[$requestedPage];
}

$templateFile = TEMPLATE_DIR . $pageToLoad . '.php';

// --- Inclusion ---

// Ensure the template file exists before including
if (file_exists($templateFile)) {
    include $templateFile;
} else {
    // Optionally, include a 404 page or display an error
    // For simplicity, we'll just show a message.
    // In a real CMS, you might have a '404.php' template.
    echo "<h1>404 Not Found</h1>";
    echo "<p>The requested page '" . htmlspecialchars($requestedPage ?? $defaultPage) . "' could not be found.</p>";
}

?>